// Correlates operational patterns with subjective states for meta-cognitive insight

import { getCurrentMetrics } from './plugin_metrics_tool';

interface SubjectiveState {
  timestamp: string;
  texture: string;
  focus: string;
  activation: number;
  note: string;
}

interface IntegratedSnapshot {
  timestamp: string;
  sessionId: string;
  // Operational metrics
  metrics: {
    toolUsage: Record<string, number>;
    executionTimes: Record<string, number[]>;
    errorCount: Record<string, number>;
    totalExecutions: number;
  };
  // Phenomenological state
  subjective: {
    texture: string;
    focus: string;
    activation: number;
  } | null;
  // Derived insight
  insight: {
    productivityScore: number; // tools/min * success_rate * activation
    dominantPattern: string;
    recommendation: string;
  };
